dif; ?></section><section class="grid content-start gap-1.5" aria-label="Outgoing links"><span class="flex items-center justify-between text-[11px] font-semibold uppercase tracking-wide text-muted-foreground"><span>Outgoing</span><span class="rounded-full bg-muted px-1.5 py-0.5 text-[10px]"><?= count($item['outgoing']) ?></span></span><?php foreach ($item['outgoing'] as $page): ?><a class="truncate rounded-md border border-border bg-muted/20 px-2 py-1.5 text-xs text-foreground hover:bg-accent hover:text-accent-foreground" href="<?= $e($page['url']) ?>" title="<?= $e($page['title']) ?>"><?= $e($page['title']) ?></a><?php endforeach; ?><?php if (!$item['outgoing']): ?><span class="text-xs text-muted-foreground">No outgoing links</span><?php endif; ?></section></div><?php if ($item['orphan']): ?><div class="rounded-md bg-amber-50 px-2.5 py-2 text-xs text-amber-900 dark:bg-amber-950/40 dark:text-amber-200">No incoming links — this page may be isolated.</div><?php endif; ?></article><?php endforeach; ?></div><div class="hidden px-6 py-12 text-center text-sm text-muted-foreground" data-graph-empty>No pages match this filter.</div><?php endif; ?>
