<script nonce="<?= $e($csp_nonce ?? '') ?>">(() => { const input = document.querySelector('[data-graph-filter]'); const items = [...document.querySelectorAll('[data-graph-item]')]; const empty = document.querySelector('[data-graph-empty]'); input?.addEventListener('input', () => { const query = input.value.trim().toLowerCase(); let visible = 0; items.forEach(item => { const match = !query || item.dataset.search.includes(query); item.classList.toggle('hidden', !match); if (match) visible++; }); empty?.classList.toggle('hidden', visible !== 0); }); })();</script>
